vim.api.nvim_create_user_command("YankVimPathLineNum", function()
	local relative_path = vim.fn.fnamemodify(vim.fn.expand("%"), ":~:.")
	local line_number = vim.fn.line(".")
	local path_line_num = relative_path .. ":" .. line_number
	vim.fn.setreg("+", path_line_num)
	vim.fn.setreg('"', path_line_num)
	vim.print("Copied '" .. path_line_num .. "' to clipboard")
end, {})

vim.api.nvim_create_user_command("YankRefToFilePath", function()
	local relative_path = vim.fn.fnamemodify(vim.fn.expand("%"), ":~:.")
	local line_number = vim.fn.line(".")
	local file_ref = "@" .. relative_path
	vim.fn.setreg("+", file_ref)
	vim.fn.setreg('"', file_ref)
	vim.print("Copied '" .. file_ref .. "' to clipboard")
end, {})

vim.keymap.set(
	"n",
	"<space>yrf",
	":YankRefToFilePath<CR>",
	{ desc = "[Y]ank Claude-friendly [r]eference to [f]ile path" }
)

vim.api.nvim_create_user_command("YankRefToFileLineNum", function(opts)
	local relative_path = vim.fn.fnamemodify(vim.fn.expand("%"), ":~:.")
	local path_line_ref
	if opts.range == 0 then
		-- No range provided, use current line
		local line_number = vim.fn.line(".")
		path_line_ref = "@" .. relative_path .. "#L" .. line_number
	elseif opts.line1 == opts.line2 then
		-- Single line selected
		path_line_ref = "@" .. relative_path .. "#L" .. opts.line1
	else
		-- Range selected
		path_line_ref = "@" .. relative_path .. "#L" .. opts.line1 .. "-" .. opts.line2
	end
	vim.fn.setreg("+", path_line_ref)
	vim.fn.setreg('"', path_line_ref)
	vim.print("Copied '" .. path_line_ref .. "' to clipboard")
end, { range = true })

vim.keymap.set(
	"n",
	"<space>yrl",
	"<Cmd>YankRefToFileLineNum<CR>",
	{ desc = "Yank agent-friendly file and line number reference" }
)
vim.keymap.set(
	"v",
	"<space>yrl",
	":YankRefToFileLineNum<CR>",
	{ desc = "Yank agent-friendly file and line range reference" }
)

