vim.api.nvim_create_user_command("ToggleTodo", function()
	local word = vim.fn.expand("<cword>")
	if word == "TODO" then
		vim.cmd('normal! "_ciwDONE')
		vim.cmd("normal! b") -- I added this to move the cursor back after replacement
	elseif word == "DONE" then
		vim.cmd('normal! "_ciwTODO')
		vim.cmd("normal! b")
	end
end, {})

vim.keymap.set("n", "tt", ":ToggleTodo<CR>", { desc = "Toggle TODO/DONE" })

