-- This is used to show LSP diagnostics on cursorhold:
vim.api.nvim_create_autocmd({ "CursorHold" }, {
	pattern = "*",
	callback = function()
		vim.diagnostic.open_float({ scope = "cursor", focusable = true })
	end,
})
vim.opt.updatetime = 500 -- Trigger CursorHold after 500ms of inactivity

vim.api.nvim_create_user_command("InsertDate", function()
	local date = os.date("%Y-%m-%d")
	vim.api.nvim_put({ date }, "c", false, true)
end, {})

vim.keymap.set("n", "<space>id", ":InsertDate<CR>", { desc = "Insert current date (YYYY-MM-DD)" })

vim.api.nvim_create_user_command("InsertTime", function()
	local time = os.date("%H:%M")
	vim.api.nvim_put({ time }, "c", false, true)
end, {})

vim.keymap.set("n", "<space>it", ":InsertTime<CR>", { desc = "Insert current time (HH:MM)" })

