-- <markdown_keymaps>
vim.api.nvim_create_autocmd("FileType", {
	pattern = "markdown",
	callback = function(ev)
		vim.keymap.set("x", "_", [[c_<C-r>"_<Esc>]], {
			buffer = ev.buf,
			desc = "Wrap selection in markdown italics",
		})
		vim.keymap.set("x", "*", [[c**<C-r>"**<Esc>]], {
			buffer = ev.buf,
			desc = "Wrap selection in markdown bold",
		})
		vim.keymap.set("x", "`", [[c`<C-r>"`<Esc>]], {
			buffer = ev.buf,
			desc = "Wrap selection in markdown inline code",
		})

		vim.keymap.set("x", "~", [[c~~<C-r>"~~<Esc>]], {
			buffer = ev.buf,
			desc = "Wrap selection in markdown strikethrough",
		})
	end,
})

-- </markdown_keymaps>
